import org.elasticsearch.action.admin.indices.create.CreateIndexRequest;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightField;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.TermsAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.AvgAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.MaxAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.MinAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.SumAggregationBuilder;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.*;

@Service
public class ElasticsearchService {

    @Autowired
    private RestHighLevelClient client;

    @Value("${elasticsearch.index.products}")
    private String productIndex;

    @Value("${elasticsearch.index.queries}")
    private String queryIndex;

    public void createProductIndex() throws IOException {
        GetIndexRequest request = new GetIndexRequest(productIndex);
        boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createRequest = new CreateIndexRequest(productIndex);
            createRequest.mapping(productMapping(), XContentType.JSON);
            client.indices().create(createRequest, RequestOptions.DEFAULT);
        }
    }

    public void createQueryIndex() throws IOException {
        GetIndexRequest request = new GetIndexRequest(queryIndex);
        boolean exists = client.indices().exists(request, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createRequest = new CreateIndexRequest(queryIndex);
            createRequest.mapping(queryMapping(), XContentType.JSON);
            client.indices().create(createRequest, RequestOptions.DEFAULT);
        }
    }

    public void indexProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest(productIndex);
        request.id(product.getId().toString());
        request.source(product.toJson(), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void indexQuery(SearchQuery query) throws IOException {
        IndexRequest request = new IndexRequest(queryIndex);
        request.id(UUID.randomUUID().toString());
        request.source(query.toJson(), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            IndexRequest request = new IndexRequest(productIndex);
            request.id(product.getId().toString());
            request.source(product.toJson(), XContentType.JSON);
            bulkRequest.add(request);
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new RuntimeException("Bulk indexing failed: " + response.buildFailureMessage());
        }
    }

    public SearchResult searchProducts(SearchRequestDTO requestDTO) throws IOException {
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (requestDTO.getQuery() != null && !requestDTO.getQuery().isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(requestDTO.getQuery(), "name", "description", "brand"));
        }

        if (requestDTO.getFilters() != null) {
            for (Map.Entry<String, List<String>> filter : requestDTO.getFilters().entrySet()) {
                if (filter.getValue() != null && !filter.getValue().isEmpty()) {
                    boolQuery.filter(QueryBuilders.termsQuery(filter.getKey(), filter.getValue()));
                }
            }
        }

        if (requestDTO.getMinPrice() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price").gte(requestDTO.getMinPrice()));
        }

        if (requestDTO.getMaxPrice() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price").lte(requestDTO.getMaxPrice()));
        }

        searchSourceBuilder.query(boolQuery);
        searchSourceBuilder.from(requestDTO.getFrom());
        searchSourceBuilder.size(requestDTO.getSize());

        if (requestDTO.getSortBy() != null && !requestDTO.getSortBy().isEmpty()) {
            searchSourceBuilder.sort(requestDTO.getSortBy(), requestDTO.getSortOrder());
        }

        HighlightBuilder highlightBuilder = new HighlightBuilder();
        highlightBuilder.field("name");
        highlightBuilder.field("description");
        highlightBuilder.field("brand");
        highlightBuilder.preTags("<em>");
        highlightBuilder.postTags("</em>");
        searchSourceBuilder.highlighter(highlightBuilder);

        addAggregations(searchSourceBuilder, requestDTO);

        SearchRequest searchRequest = new SearchRequest(productIndex);
        searchRequest.source(searchSourceBuilder);

        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);
        return buildSearchResult(response, requestDTO);
    }

    private void addAggregations(SearchSourceBuilder searchSourceBuilder, SearchRequestDTO requestDTO) {
        TermsAggregationBuilder brandAgg = AggregationBuilders.terms("brands").field("brand").size(100);
        searchSourceBuilder.aggregation(brandAgg);

        TermsAggregationBuilder categoryAgg = AggregationBuilders.terms("categories").field("category").size(100);
        searchSourceBuilder.aggregation(categoryAgg);

        MinAggregationBuilder minPriceAgg = AggregationBuilders.min("min_price").field("price");
        searchSourceBuilder.aggregation(minPriceAgg);

        MaxAggregationBuilder maxPriceAgg = AggregationBuilders.max("max_price").field("price");
        searchSourceBuilder.aggregation(maxPriceAgg);

        AvgAggregationBuilder avgPriceAgg = AggregationBuilders.avg("avg_price").field("price");
        searchSourceBuilder.aggregation(avgPriceAgg);

        SumAggregationBuilder totalSalesAgg = AggregationBuilders.sum("total_sales").field("sales_count");
        searchSourceBuilder.aggregation(totalSalesAgg);
    }

    private SearchResult buildSearchResult(SearchResponse response, SearchRequestDTO requestDTO) {
        List<Product> products = new ArrayList<>();
        Map<String, List<String>> facets = new HashMap<>();
        Map<String, Object> aggregations = new HashMap<>();

        for (SearchHit hit : response.getHits()) {
            Product product = Product.fromJson(hit.getSourceAsString());
            product.setHighlightedFields(extractHighlightedFields(hit));
            products.add(product);
        }

        extractAggregations(response, aggregations);
        extractFacets(response, facets);

        return new SearchResult(products, response.getHits().totalHits.value, aggregations, facets);
    }

    private Map<String, List<String>> extractHighlightedFields(SearchHit hit) {
        Map<String, List<String>> highlightedFields = new HashMap<>();
        Map<String, HighlightField> highlightFields = hit.getHighlightFields();
        if (highlightFields != null) {
            for (Map.Entry<String, HighlightField> entry : highlightFields.entrySet()) {
                String fieldName = entry.getKey();
                HighlightField highlightField = entry.getValue();
                if (highlightField != null && highlightField.fragments() != null) {
                    List<String> fragments = new ArrayList<>();
                    for (org.elasticsearch.search.fetch.subphase.highlight.HighlightField fragment : highlightField.fragments()) {
                        fragments.add(fragment.string());
                    }
                    highlightedFields.put(fieldName, fragments);
                }
            }
        }
        return highlightedFields;
    }

    private void extractAggregations(SearchResponse response, Map<String, Object> aggregations) {
        if (response.getAggregations() != null) {
            for (var aggregation : response.getAggregations()) {
                aggregations.put(aggregation.getName(), aggregation);
            }
        }
    }

    private void extractFacets(SearchResponse response, Map<String, List<String>> facets) {
        if (response.getAggregations() != null) {
            for (var aggregation : response.getAggregations()) {
                if (aggregation.getName().equals("brands")) {
                    facets.put("brand", extractTermsAggregation(aggregation));
                } else if (aggregation.getName().equals("categories")) {
                    facets.put("category", extractTermsAggregation(aggregation));
                }
            }
        }
    }

    private List<String> extractTermsAggregation(var aggregation) {
        List<String> terms = new ArrayList<>();
        var termsAgg = (org.elasticsearch.search.aggregations.bucket.terms.Terms) aggregation;
        for (var bucket : termsAgg.getBuckets()) {
            terms.add(bucket.getKeyAsString());
        }
        return terms;
    }

    public void updateProduct(Product product) throws IOException {
        UpdateRequest request = new UpdateRequest(productIndex, product.getId().toString());
        request.doc(product.toJson(), XContentType.JSON);
        client.update(request, RequestOptions.DEFAULT);
    }

    public void deleteProduct(Long id) throws IOException {
        client.delete(
                new org.elasticsearch.action.delete.DeleteRequest(productIndex, id.toString()),
                RequestOptions.DEFAULT
        );
    }

    private String productMapping() {
        return "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"long\"},\n" +
                "    \"name\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"description\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"brand\": {\"type\": \"keyword\"},\n" +
                "    \"category\": {\"type\": \"keyword\"},\n" +
                "    \"price\": {\"type\": \"float\"},\n" +
                "    \"sales_count\": {\"type\": \"integer\"},\n" +
                "    \"in_stock\": {\"type\": \"boolean\"},\n" +
                "    \"tags\": {\"type\": \"keyword\"}\n" +
                "  }\n" +
                "}";
    }

    private String queryMapping() {
        return "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"query\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"timestamp\": {\"type\": \"date\"},\n" +
                "    \"user_id\": {\"type\": \"keyword\"},\n" +
                "    \"filters\": {\"type\": \"keyword\"},\n" +
                "    \"result_count\": {\"type\": \"integer\"}\n" +
                "  }\n" +
                "}";
    }
}

